INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027d63e3c98b0941765b24', '房间干净整洁舒适', '["https://dimg04.c-ctrip.com/images/0230212000dsi0fwuF2BB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000dshsf0o5781_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-26', '花园大床房', '大床房', '商务出差', 8, 0, 1, 4, '["卫生状况","整体满意度"]'::jsonb, '卫生状况', '整体满意度', NULL),
('68027d63e3c98b0941765b25', '服务很好。老牌五星酒店，半数服务员都是外籍的，为了方便全球各地的游客，这个细节很好??卫生和设施也都很好，虽然外观看着旧了一些，但内部装修非常好，以后还会再入住！', '["https://dimg04.c-ctrip.com/images/0231112000cw6rv1t326E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z12000cw6rsxg03DD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m12000cw6n38hB37D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000cw6sng801A0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-09', '花园大床房', '大床房', '家庭亲子', 81, 0, 32, 8, '["整体满意度","前台服务","卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况'),
('68027d63e3c98b0941765b26', '无论停车、服务、设施还是环境，各方面都OK的五星级酒店，送了花水果饮料，尤其是那个花园，早晨起来逛逛太美了，真是超级喜欢和享受的一天哦。', '["https://dimg04.c-ctrip.com/images/0234l12000culilcbE741_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000culxrerD200_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000culo0laCBB8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000culz1daBA50_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-02', '花园双床房', '双床房', '情侣出游', 68, 0, 92, 6, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('68027d63e3c98b0941765b27', '房间是发霉的，关于房间的其它就不想多说了！服务态度谈吐有点崇洋媚外的感觉，而且退房时的前台接待自我感觉莫名其妙的良好，一副不耐烦的样子！唯一值得表扬一点，地铁交通是便利的！', '["https://dimg04.c-ctrip.com/images/0236912000coeho8w5508_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000coebvmk36AC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236e12000coei3ap5DCA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000coed8t6547C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.7, 2, '2023-12-04', '花园双床房', '双床房', '家庭亲子', 86, 9, 9, 7, '["房间设施","前台服务","交通便利性"]'::jsonb, '房间设施', '前台服务', '交通便利性'),
('68027d63e3c98b0941765b28', '花园酒店名不虚传，宽敞的大堂，有瀑布的大花园，内容丰富的博物馆，无处不在的美丽鲜花，还有贴心的服务，让人宾至如归，下次再来??', '["https://dimg04.c-ctrip.com/images/0233912000cvrxj57ABC9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000cvrxjskD92F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000cvrxhc5C5AA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236u12000cvrxj5vC382_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-07', '红棉大床套房', '套房', '家庭亲子', 63, 0, 8, 8, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('68027d63e3c98b0941765b29', '工作人员都很热情，Marry还帮我们布置了纪念日房间，服务态度非常好??
房间干净明亮，高楼层很安静
酒店博物馆也很有意思
可惜没时间逛后花园', '["https://dimg04.c-ctrip.com/images/0232l12000fkqrvos164C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-15', '花园大床房', '大床房', '情侣出游', 71, 0, 5, 7, '["前台服务","卫生状况","安静程度"]'::jsonb, '前台服务', '卫生状况', '安静程度'),
('68027d6ee3c98b0941765b2a', '携程活动时囤的券，非常划算。酒店景观很棒，入住时庆生，升级了房型。升级后的房型蛮大，做了生日布置，满意。checkin时等待时间有点长，还好我们有行政酒廊待遇，就先上去喝下午茶了。整体服务还不错，特别是行政酒廊的小姐姐，服务非常好，还记住我们喝的饮料。第二天恰逢周末，早餐大排长队，无奈只能打包回房间吃，这点看评论酒店一直有这个问题，希望能改善。', '["https://dimg04.c-ctrip.com/images/0236a12000cm6itmp1F11_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236q12000cm6f71u3824_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000cm6cyo465E4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236y12000cm6b41v959A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-11-22', '花园双床房', '双床房', '家庭亲子', 173, 0, 6, 9, '["性价比","景观/朝向","退房/入住效率"]'::jsonb, '性价比', '景观/朝向', '退房/入住效率'),
('68027d6ee3c98b0941765b2b', '自助早餐真的很一般 品种非常少 花园很美 大堂装饰的也很有新年气氛 服务也不错', '["https://dimg04.c-ctrip.com/images/0232f12000d8ay4xg67B9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-02-17', '花园双床房', '双床房', '家庭亲子', 39, 0, 5, 6, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68027d6ee3c98b0941765b2c', '不喜欢老酒店，虽然房间是最近翻新过的，但是满足父母情怀之后以后不会再选择啦。酒店其实不小，但是人很多，很吵。', '["https://dimg04.c-ctrip.com/images/0235g12000dln5gij0924_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000dln2lfd426B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236312000dlmzhge2542_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2024-04-06', '红棉双床套房', '套房', '家庭亲子', 54, 0, 8, 6, '["安静程度","整体满意度"]'::jsonb, '安静程度', '整体满意度', NULL),
('68027d6ee3c98b0941765b2d', '很满意，服务非常好，交通很方便，下次再来住，楼下美食非常多，广州太好吃了', '["https://dimg04.c-ctrip.com/images/0233112000d9czlul945F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000d9d2e6n2872_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000d9db70lB38A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-21', '花园双床房', '双床房', '家庭亲子', 36, 0, 10, 5, '["整体满意度","交通便利性","周边配套"]'::jsonb, '整体满意度', '交通便利性', '周边配套'),
('68027d6ee3c98b0941765b2e', '设施：酒店设施齐全，功能完好。
卫生：房间宽敞舒适，卫生整洁。
环境：花园环境美丽，大堂华丽。
服务：各处服务人员热情周到，待客如宾。', '["https://dimg04.c-ctrip.com/images/0232y12000cxy8v335F24_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000cxy94s34C3D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000cxy91qsEC04_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-15', '红棉大床套房', '套房', '商务出差', 67, 0, 3, 6, '["整体满意度","房间设施","卫生状况"]'::jsonb, '整体满意度', '房间设施', '卫生状况'),
('68027d6ee3c98b0941765b2f', '超值的享受！
住酒店这么多年，我认为花园酒店是我迄今为止住过最好的酒店。
现在太难找到一家这么有文化底蕴的酒店了。
如果外地游客来广州玩，强烈建议就住这里，可以浓缩地快速地了解广府文化。', '["https://dimg04.c-ctrip.com/images/0231212000ciwb8eb18EC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231812000ciwiy28F092_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000ciw7qch2D4C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231s12000ciwbpcnE3C8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000ciweutf592D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232n12000ciwbnoa775E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000ciwd31f0C84_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232n12000ciwbsi39B9C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000ciwfjmxF444_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-06', '花园大床房', '大床房', '家庭亲子', 93, 0, 3, 7, '["整体满意度","性价比"]'::jsonb, '整体满意度', '性价比', NULL),
('68027d6ee3c98b0941765b30', '来广州探亲，这次定的花园酒店，大堂还是那么华丽，房间干净，那么多年保持得非常好??附近喝茶也非常方便，下次还会来！', '["https://dimg04.c-ctrip.com/images/0233y12000cxnxzwc22C4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000cxny2xf1597_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000cxnxx9a8000_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-14', '花园大床房', '大床房', '其他', 57, 0, 13, 7, '["整体满意度","卫生状况","周边配套"]'::jsonb, '整体满意度', '卫生状况', '周边配套'),
('68027d6ee3c98b0941765b31', '房间布草很舒服。服务很好??', '["https://dimg04.c-ctrip.com/images/0236312000dn363lg6A50_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000dn374urB22B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232f12000dn35g36E451_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-10', '花园大床房', '大床房', '独自旅行', 14, 0, 18, 4, '["房间设施","前台服务"]'::jsonb, '房间设施', '前台服务', NULL),
('68027d6ee3c98b0941765b32', '预售套餐特别划算，1050的红棉大床房大概有100平，两个卫生间，住起来很舒服，赠送的500无门槛餐券也性价比极高。

花园酒店的花园有苏州园林的风采，瀑布和园林相呼应，心旷神怡', '["https://dimg04.c-ctrip.com/images/0232t12000cmloeor0681_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234412000cmlr2l4B4E0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q12000cmlyzn5CD2A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000cmm6iwx46E3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k12000cmm1k20F59D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-24', '红棉大床套房', '套房', '情侣出游', 89, 0, 1, 8, '["性价比","餐饮设施","整体满意度"]'::jsonb, '性价比', '餐饮设施', '整体满意度'),
('68027d6ee3c98b0941765b33', '非常的好位置也方便

非常的好位置也方便
非常的好位置也方便

非常的好位置也方便

非常的好位置也方便

非常的好位置也方便', '["https://dimg04.c-ctrip.com/images/0233b12000d0y1mf7B1CE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000d0xz0kcDDD8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235a12000d0yg43a5842_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234412000d0ye2u5E4E2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-24', '花园大床房', '大床房', '商务出差', 63, 0, 25, 2, '["交通便利性","周边配套"]'::jsonb, '交通便利性', '周边配套', NULL),
('68027d7ae3c98b0941765b34', '很差 无敌差 毫无底线的差
客服卫生：窗边椅上精癍懂得都懂，桌面上的灰尘和脏恨也证明没有擦过
更绝的是旁边的工地，如视频一所展示，打桩到晚上十点多 早上七点开撞，保证吵得你心态崩掉，中午都不停工的
最绝的是酒店处理，怕你听不清楚工地有多吵，要我从16楼侧对工地的房调到12楼正对工地，如视频二所展示。保证你看的更清，听的更清！10:53再让调房直接说没房要等打扫，13:06才说打扫好，主打一个拖字诀的妙用！妙啊妙啊！
该酒店对会员礼遇也很绝，请大家看看金卡会员的礼遇，再和大家说说这酒店干了些什么，入住退房专享接待通道，没有，管你什么会员，去排队；欢迎水果，没有；行政酒廊，不开了；呵呵呵不想搞会员你们可以不搞啊，啥都不给算什么，算欺诈嘛？
服务：该酒店服务更是下流，本应在入住时准确告知早餐餐厅位置等信息，前台没说，也没说早餐还有在30楼。第二天吃早餐时来到一楼，一楼的热情接待外国人，中国人就说三十楼没人排队，可以上三十楼吃，去到好家伙，30楼人更多，咋的，你们酒店员工都主打一个骗嘛？从会员礼遇骗到服务骗到设施？
啊对对对，你们酒店是不缺游客不缺外宾，中国人在你这狗都不是，会员在你这狗都不如，这条差评你们也可以不care，但麻烦你们做好准备好回复我向文旅部门、市场部门、集团的投诉哈', '["https://dimg04.c-ctrip.com/images/0206o12000cjbenvi68EF_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0202912000cjbenvo2BF4_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0235412000cjb0vw60A2D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000cjaxnm764C3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000cjbbxkpFC80_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000cjb78eeE60E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t12000cjb8etrE62C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m12000cjbbfc3D116_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1, 1, '2023-11-08', '红棉大床套房', '套房', '朋友出游', 546, 25, 0, 9, '["安静程度","前台服务","卫生状况"]'::jsonb, '安静程度', '前台服务', '卫生状况'),
('68027d7ae3c98b0941765b35', '入住人很多，入住办了半个小时，大堂没有沙发，老人孩子就只能站在旁边等着，押金收的挺快，昨天一早退房就说可以了，押金原路返回，过了2天了，还没退，给前台打电话永远没人接，总之不适合家庭出游，这酒店只适合商务宴请接待外宾，带孩子老人出游慎选', '["https://dimg04.c-ctrip.com/images/0234e12000cjrx754B6B0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000cjryu2b418A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000cjrvle2B4ED_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-11-10', '花园大床房', '大床房', '家庭亲子', 118, 1, 6, 8, '["退房/入住效率","前台服务","整体满意度"]'::jsonb, '退房/入住效率', '前台服务', '整体满意度'),
('68027d7ae3c98b0941765b36', '贝聿铭大师的杰作，虽然已经有40年历史，但仍没觉得过时。花园四季如春，锦鲤满池，环境优雅，个人感觉是广州最有味道的酒店。', '["https://dimg04.c-ctrip.com/images/0236812000cvr1d031698_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232n12000cvr1vgmA2D8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231212000cvqyr6n27CF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234g12000cvqz35k430A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234e12000cvqx05w2A07_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-07', '花园双床房', '双床房', '家庭亲子', 60, 0, 98, 8, '["整体满意度","景观/朝向"]'::jsonb, '整体满意度', '景观/朝向', NULL),
('68027d7ae3c98b0941765b37', '总体十分满意！基本每次出差都会选花园酒店落脚。地理位置优越，服务也比较好，酒店本身的厨房出菜品质就很好。美中不足酒店年头有点久了，有的房间是有点老旧的感觉…', '["https://dimg04.c-ctrip.com/images/0230x12000cu0plq7A807_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235012000cu0avs32657_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231e12000cu0giie1BF5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-12-30', '红棉大床套房', '套房', '商务出差', 78, 0, 85, 8, '["整体满意度","交通便利性","餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施'),
('68027d7ae3c98b0941765b38', '在携程上买了预售的红棉大床房加500餐饮额度的套餐，刚好来广州办事就预约了一个周六入住。最近好像广交会，入住的各国友人比较多，办入住的时候在前台等了很久，而且大厅也没有沙发让同伴坐一下的，这点体验不是很好，另外早餐也是在瀑布餐厅门口等了很久。酒店其他方面都还可以吧，硬件不错，床很舒服。', '["https://dimg04.c-ctrip.com/images/0235i12000cjc7l4n70B2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231m12000cjc3r8bDEA4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235a12000cjc36ck4B15_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234112000cjc3fp03551_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000cjbvbsb8C3F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000cjc3phtDCFE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-11-08', '红棉大床套房', '套房', '朋友出游', 143, 0, 1, 7, '["前台服务","退房/入住效率","餐饮设施"]'::jsonb, '前台服务', '退房/入住效率', '餐饮设施'),
('68027d7ae3c98b0941765b39', '广州老字号酒店，服务很好，酒店很漂亮很大气，办理入住的小哥哥很亲切看我们带孩子还帮我升级了房间，下次来广州还会来住这家', '["https://dimg04.c-ctrip.com/images/0234k12000cvknk720B5F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000cvknsopA0EF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000cvknpvf9839_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-06', '花园双床房', '双床房', '家庭亲子', 59, 0, 9, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027d7ae3c98b0941765b3a', '花园酒店是有历史文化底蕴的，交通方便，大堂非常富丽堂皇，服务也好，唯一就是早餐和自助晚餐感觉一般吧', '["https://dimg04.c-ctrip.com/images/0233f12000d0sbhm430EA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-24', '花园双床房', '双床房', '家庭亲子', 49, 0, 9, 7, '["交通便利性","整体满意度","餐饮设施"]'::jsonb, '交通便利性', '整体满意度', '餐饮设施'),
('68027d7ae3c98b0941765b3b', '著名的老酒店，春节?气氛浓郁，服务很好。餐厅价格好吃但很贵。房间地漏反臭', '["https://dimg04.c-ctrip.com/images/0234312000d9i2nzm4805_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000d9i1xxkAB77_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235012000d9htwh4EFD2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000d9hp7ptA6C5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000d9i01xz53AE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234j12000d9hsawk66F0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2024-02-21', '城央绿意双床房', '双床房', '独自旅行', 36, 0, 45, 6, '["房间设施","餐饮设施","前台服务"]'::jsonb, '房间设施', '餐饮设施', '前台服务'),
('68027d7ae3c98b0941765b3c', '虽然是老五星酒店，但整体服务、住宿环境都还是不错的。酒店环境是亮点，室外有假山、瀑布，有小桥流水，有锦鲤成群；室内有酒店历史陈列馆，有各种主题小馆。酒店地理位置也很好，出门就有地铁、公交。酒店床垫、隔音、空调都挺好的。稍有不足的是前台办理入住有点慢，部分员工服务意识还有待提升。', '["https://dimg04.c-ctrip.com/images/0232n12000d6cd9o28AA3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230o12000d6cqs85302C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236w12000d6cq5qkF451_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-02-11', '花园双床房', '双床房', '其他', 139, 0, 1, 9, '["整体满意度","交通便利性","房间设施"]'::jsonb, '整体满意度', '交通便利性', '房间设施'),
('68027d7ae3c98b0941765b3d', '服务很专业，环境优美，后花园非常漂亮。', '["https://dimg04.c-ctrip.com/images/0230f224x8ubi89na6113_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-24', '花园大床房', '大床房', '朋友出游', 19, 0, 7, 5, '["整体满意度","公共设施"]'::jsonb, '整体满意度', '公共设施', NULL),
('68027d85e3c98b0941765b3e', '到酒店发现酒店后面在施工，入住时，提出需要安静房间，前台给升级为粤韵房型。房间很卫生舒适，连洗漱用品都拼成了一幅画。酒店环境优美，特意去花园逛逛，很惬意。酒店里有博物馆，还在那里看见很有趣的玩具，给小朋友买了一个漂亮的拼车。在酒店遇到的每位服务人员都和善礼貌，会主动询问是否需要帮助。就是酒店的早餐稍显简单，味道一般。因为广交会，门口有舞狮祈福，舞狮班的人特别和善，可以帮助拍照合影。值得一住的酒店', '["https://dimg04.c-ctrip.com/images/0232212000citmh8sB859_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235a12000citg6tc8C19_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233k12000citc2ss9119_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232i12000cithhqhC657_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-06', '红棉大床套房', '套房', '其他', 199, 0, 24, 9, '["整体满意度","前台服务","安静程度"]'::jsonb, '整体满意度', '前台服务', '安静程度'),
('68027d85e3c98b0941765b3f', '很贴心的酒店服务，下次出差还会选择出花园酒店', '["https://dimg04.c-ctrip.com/images/0231t12000di2mzj72B48_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236w12000di2nwct5F6D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-25', '红棉大床套房', '套房', '商务出差', 22, 0, 4, 4, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027d85e3c98b0941765b40', '来广州住的第一个酒店，选择有很有历史底蕴的花园酒店，之前还担心这么“老”的酒店会不会有点陈旧，到了发现保养地还真的不错，前厅很气派，很有老牌酒店的韵味，国庆节入住，因为拖家带口，有老有小，选择付费升级了套房，第一眼的感觉很不错。酒店的服务很五星，有自己的博物馆，满满的历史感，还有邓爷题词的酒店名，户外游泳池已开放，国庆入住的几天，游泳的人也不多，可能都出去玩了，游泳池的服务到位。缺点的话，就是酒店确实年纪大了，有些隐蔽设施会有点问题，比如一间房的电话不能使用，另一间房的空调管堵塞，导致最后一天出现了漏水，湿了一片，不过响应及时，第一天的双床等了半天才打扫完，有点不爽，其他入住期间都很满意。', '["https://dimg04.c-ctrip.com/images/0230o12000cc8y9bv80A3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000cc8yvzoF309_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237412000cc8xl8c659C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000cc8yvzq71CF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000cc8u8xdD77D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235n12000cc8sjn892BB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231212000cc8ws6x1DAA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000cc8tcz68981_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000cc8vurlC95D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-06', '花园双床房', '双床房', '家庭亲子', 298, 0, 4, 9, '["房间设施","整体满意度","客房服务"]'::jsonb, '房间设施', '整体满意度', '客房服务'),
('68027d85e3c98b0941765b41', '不愧是老牌大酒店，装修大气上档次，房间干净整洁，床及床上用品非常的舒服，真的是一夜好眠，推荐大家一定要去尝尝他家的中餐菜品，绝了??！', '["https://dimg04.c-ctrip.com/images/0200812000dcmq9ibD3AA_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0231k12000dcmp3294F9D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000dcmon4h7CD1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000dcmp32c5E83_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235412000dcmp32fB8EF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236w12000dcmp32jBCCB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232l12000dcmp14gD314_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235k12000dcmpalnE962_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235512000dcmp32tB312_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-05', '花园双床房', '双床房', '家庭亲子', 67, 0, 7, 8, '["房间设施","整体满意度","卫生状况"]'::jsonb, '房间设施', '整体满意度', '卫生状况'),
('68027d85e3c98b0941765b42', '性价比一点也不好，一千多的房间比亚朵还差，最好和服务员沟通换了套房！房间卫生打扫需改善，灰尘不少！！', '["https://dimg04.c-ctrip.com/images/0230s12000cxxvpqy7C8A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3, 3, '2024-01-15', '花园双床房', '双床房', '家庭亲子', 50, 0, 13, 6, '["性价比","卫生状况","客房服务"]'::jsonb, '性价比', '卫生状况', '客房服务'),
('68027d85e3c98b0941765b43', '环境很好，设施不陈旧，升级了套房特别感谢。四楼的博物馆周一闭馆，最好提前一天预约。花园晚上逛更有氛围', '["https://dimg04.c-ctrip.com/images/0234x12000cxx3odq4FAD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000cxx46t6A000_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000cxx3xvb9AB7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000cxx3zveF2D9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234412000cxx3zvu8AE9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236l12000cxx3x6g7FF9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000cxx3r153CE0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000cxx4c4rAF4F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000cxx4hp50159_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-15', '花园大床房', '大床房', '家庭亲子', 50, 0, 9, 7, '["整体满意度","房间设施","周边配套"]'::jsonb, '整体满意度', '房间设施', '周边配套'),
('68027d85e3c98b0941765b44', '顶层行政酒廊不错，下午茶和晚间的欢乐时光都很喜欢。小蛋糕选择很多，看着精致实际口味也都不错。Carrie和Lena很亲切，服务有求必应。', '["https://dimg04.c-ctrip.com/images/0236t12000dfpf8uz84C2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232v12000dfpfv499CA5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h12000dfpbjsmF52B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m12000dfpf8v13E79_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000dfp941oBA8E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000dfpcv5vDBF2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231612000dfoz8957EB8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233112000dfp617rEB8F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232v12000dfoq3rmDC14_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-17', '花园双床房', '双床房', '家庭亲子', 68, 0, 2, 8, '["餐饮设施","前台服务"]'::jsonb, '餐饮设施', '前台服务', NULL),
('68027d85e3c98b0941765b45', '朋友幸运Li，在酒店工作，见她推荐花园酒店赞不绝口，怎么也想住住看。
但过了两个月，竟然忘了评价。
白金五星名不虚传，广州花园酒店，是传闻中的天花板～
传奇酒店，华南地区唯一“白金五星”[强]，极尽奢华。
“几个米其林餐厅”和“花园博物馆”蕴含其中，拥有傲人的成绩和历史，比如：香港基本法的起草，亚运会的总部酒店，接待数位各国首相领导人等等；
??行政酒廊出花园便是锦鲤亭台瀑布，瀑布餐厅便是真正在造景瀑布旁边用餐，另外还有30楼旋转餐厅等共计9个餐厅酒吧等；
下午在锦鲤酒廊的Happy Hour其实和瀑布餐厅相连，也是边欣赏美景边用餐，晚上还是轻酒吧可小酌。
[玫瑰]或许因为年代有点久远，的确没有洲际瑰丽等那样的现代，但是花园的历史随着光阴反而越发有魅力。
在房间返修以后，大气依旧在，而大厅走廊各样的昂贵装饰和摆件，也及其奢华，看起来有老香港的感觉，但一切又很新。
总之就是那种，看上去浮夸奢侈，但其实蕴藏了文化很悠久的底蕴～', '["https://dimg04.c-ctrip.com/images/0235n12000cudth6p7F86_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000cudu0tw8E13_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235812000cudr36xE592_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000cudqof63965_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231612000cudqkbzF28C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000cudp0hlA86E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231s12000cudv3ym87C2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234612000cudvusc934A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000cudttd5F536_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-01', '花园双床房', '双床房', '家庭亲子', 417, 0, 42, 9, '["整体满意度","餐饮设施","公共设施"]'::jsonb, '整体满意度', '餐饮设施', '公共设施'),
('68027d85e3c98b0941765b46', '此次广州行特意选择了老牌酒店，服务没话说，装潢很中国风，值得住店品鉴，不愧是对外窗口酒店！
房间19年重装过，整体偏向现代风，一个人商旅住宿是很刚好的，比较有安全感。
前台最近有298升级套房送宝格丽洗护的活动，为这个销售创意点赞，很值得参考的一个销售策略！', '["https://dimg04.c-ctrip.com/images/0232n12000che0vkf563E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000che3y2fA199_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234t12000chdsjyd62AF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-10-30', '花园大床房', '大床房', '商务出差', 129, 0, 11, 8, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68027d85e3c98b0941765b47', '大半年前屯的花园酒店 红棉套房套餐 圣诞期间酒店很漂亮 服务很好 位置特别方便 淘金站地铁出行 去哪儿都不太远 家人很满意 推荐', '["https://dimg04.c-ctrip.com/images/0236y12000cs2b9ye747C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234712000cs27e4775D7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000cs2aqdaF250_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000cs262671A86_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231b12000cs2ckvzB04E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-22', '红棉双床套房', '套房', '家庭亲子', 64, 0, 19, 7, '["整体满意度","交通便利性","前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务'),
('68027d95e3c98b0941765b48', '花园酒店的交通绝对方便，地铁淘金站上来就是，二楼荔湾庭餐厅品种多样，味道也好，环境岭南风，早餐一楼瀑布餐厅和30楼旋转餐厅都可以享用。', '["https://dimg04.c-ctrip.com/images/0231l12000cr1t93y448B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230p12000cr1zzit26FE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000cr1xorg0CA7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233b12000cr218ik7D1F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233j12000cr1vxjl27AF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-17', '花园大床房', '大床房', '情侣出游', 67, 1, 203, 9, '["交通便利性","餐饮设施","整体满意度"]'::jsonb, '交通便利性', '餐饮设施', '整体满意度'),
